import { useEffect, useState } from "react";

function Dashboard() {
    const [threads, setThreads] = useState([]);
    const [news, setNews] = useState([]);
    const [matches, setMatches] = useState([]);
    const [events, setEvents] = useState([]);
    const [windowWidth, setWindowWidth] = useState(window.innerWidth);

    useEffect(() => {
        fetch("/api/threads").then(res => res.json()).then(setThreads);
        fetch("/api/news").then(res => res.json()).then(setNews);
        fetch("/api/matches").then(res => res.json()).then(data => {
            if (Array.isArray(data)) {
                setMatches(data);
            } else if (data.content) {
                setMatches(data.content);
            } else {
                setMatches([]);
            }
        }).catch(() => setMatches([]));
        fetch("/api/events").then(res => res.json()).then(setEvents);

        function handleResize() {
            setWindowWidth(window.innerWidth);
        }
        window.addEventListener("resize", handleResize);
        return () => window.removeEventListener("resize", handleResize);
    }, []);

    // Set your breakpoint for hiding Threads (e.g., 800px)
    const hideThreads = windowWidth < 800;

    return (
        <main style={styles.Dashboard}>
            <div style={{display: 'flex', gap: '20px'}}>
                {!hideThreads && (
                    <div style={{flex: 1}}>
                        <h3>Threads</h3>
                        {threads.map((thread, idx) => (
                            <div key={idx} style={styles.box} onClick={() => alert(`Clicked thread: ${thread.title}`)}>
                                {thread.title}
                            </div>
                        ))}
                    </div>
                )}

                <div style={{flex: 1}}>
                    <h3>News</h3>
                    {news.map((item, idx) => (
                        <div key={idx} style={styles.box} onClick={() => alert(`Clicked news: ${item.headline}`)}>
                            {item.headline}
                        </div>
                    ))}
                </div>

                <div style={{flex: 1}}>
                    <h3>Matches</h3>
                    {matches.map((match, idx) => (
                        <div key={idx} style={styles.box} onClick={() => alert(`Clicked match: ${match.teama} vs ${match.teamb}`)}>
                            {match.teama} vs {match.teamb}<br/>
                            <small>{new Date(match.match_time).toLocaleString()}</small>
                        </div>
                    ))}
                </div>

                <div style={{flex: 1}}>
                    <h3>Events</h3>
                    {events.map((event, idx) => (
                        <div key={idx} style={styles.box} onClick={() => alert(`Clicked event: ${event.name}`)}>
                            {event.name}<br/>
                            <small>{new Date(event.event_date_time).toLocaleString()}</small>
                        </div>
                    ))}
                </div>
            </div>
        </main>
    );
}

const styles = {
    Dashboard: {
        paddingTop: '40px',
    },
    box: {
        border: '1px solid #ccc',
        padding: '10px',
        marginBottom: '10px',
        borderRadius: '0px',
        cursor: 'pointer',
        backgroundColor: '#f9f9f9',
        transition: 'background-color 0.3s ease',
    }
};

export default Dashboard;
